using DocumentFormat.OpenXml.Bibliography;
using DocumentFormat.OpenXml.Office2010.Excel;
using Firstronic.Areas.Dashboards.Models;
using System;
using System.Collections.Generic;
using System.Data.SqlClient;
using System.Data;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using static Firstronic.Areas.Planning.Models.Reports;
using System.Diagnostics;
using Firstronic.Areas.Planning.Models;

namespace Firstronic.Areas.Planning.Controllers
{
  public class StatusController : BaseSecurityController
  {
    // GET: Planning/Status
    public ActionResult Index(int? AreaID = 1, int Building_Key = 0, int year = 0, int month = 0, int day = 0)
    {
      var model = new Building_Selector();

      if (year == 0 || month == 0 || day == 0)
      {
        year = DateTime.Now.Year;
        month = DateTime.Now.Month;
        day = DateTime.Now.Day;
      }

      model.month = month;
      model.year = year;
      model.day = day;
      model.AreaID = AreaID;
      model.Building_Key = Building_Key;

      SqlParameter[] areaParameters = new SqlParameter[]{
        new SqlParameter("@AreaID",SqlDbType.Int) {Value = model.AreaID},
        new SqlParameter("@Building_Key",SqlDbType.Int) {Value = model.Building_Key},
      };

