@using System.Data;
@using System.Data.SqlClient;
@model Firstronic.Areas.Planning.Models.Reports.Building_Selector

@{
  ViewBag.Title = "Planning Balance";
  int Planning_Job_Schedule = 2396;


}

<div class="md-card">
  <div class="md-card-toolbar">
    <h3 class="md-card-toolbar-heading-text"> @ViewBag.Title </h3>
  </div>
  <div class="md-card-content">
    <div class="uk-grid" uk-grid>

      @foreach (Firstronic.Areas.Planning.Models.tbl_PART_Station Station in Model.listStations)
      {


        DataTable dtBalance = new DataTable();

        dtBalance.Columns.Add("Hour", typeof(string));
        dtBalance.Columns.Add("Job", typeof(string));
        dtBalance.Columns.Add("Part No", typeof(string));
        dtBalance.Columns.Add("Produced", typeof(string));
        dtBalance.Columns.Add("Balance", typeof(string));
        dtBalance.Columns.Add("OEE", typeof(string));

        DateTime current = DateTime.Now;
        DateTime seguida = (new DateTime(current.Year, current.Month, current.Day, current.Hour, 0, 0));

        for (int ii = 0; ii < 12; ii++)
        {
          SqlParameter[] areaParameters = new SqlParameter[]{
            new SqlParameter("@Job_Status_Key",SqlDbType.Int) {Value = Planning_Job_Schedule},
            new SqlParameter("@AreaID",SqlDbType.Int) {Value = Model.AreaID},
            new SqlParameter("@StationID",SqlDbType.Int) {Value = Station.StationID},
            new SqlParameter("@Hour_time",SqlDbType.DateTime) {Value = seguida.AddHours(+1)},
          };

          DataTable dtPlanning = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT pn.PartNumber as PartNumber,pn.PartID as PartID,Max(h.JobID) as JobID,h.JobNumber as Job,h.JobType as JobType,h.JobSide as JobSide,Count(*)-SUM(CASE WHEN DefectCodeID>1000 THEN 1 ELSE 0 END) as Qty, Cast(SUM(CASE WHEN IsGood=1 THEN 1 ELSE 0 END) as float)/(Cast(Count(*) as float)-Cast(SUM(CASE WHEN DefectCodeID>1000 THEN 1 ELSE 0 END) as float)) as FPY, SUM(CASE WHEN IsGood=1 THEN 1 ELSE 0 END) as Good, SUM(CASE WHEN IsGood=0 THEN 1 ELSE 0 END) as Bad, CAST(CASE WHEN MAX(pr.Rate)>0 THEN cast((cast(Count(*)*100 as float))/(cast(MAX(pr.Rate) as float)) as numeric(10,0))ELSE 100 END AS varchar(5)) + '%' as Eficence From PD_tbl_units_tracking h WITH(NOLOCK) INNER JOIN CS_idt_partnumbers pn WITH(NOLOCK) ON h.PartID=pn.PartID LEFT JOIN PD_tbl_stations_rates pr WITH(NOLOCK) ON h.partid=pr.partid AND pr.AreaID=@AreaID AND pr.StationID=@StationID And pr.side=h.JobSide  WHERE h.IsRework='FALSE' AND  h.StationID=@StationID AND trnDate between DATEADD(hh, -1,@Hour_time) and @Hour_time GROUP BY pn.PartNumber,pn.PartID,h.JobNumber,h.JobType,h.JobSide", areaParameters);

          if (dtPlanning.Rows.Count > 0)
          {
            foreach (DataRow rowPN in dtPlanning.Rows)
            {
              SqlParameter[] idParameters = new SqlParameter[]{
                new SqlParameter("@ID",SqlDbType.Int) {Value = (int)rowPN["JobID"]}
              };

              int JobSize = Firstronic.Framework.Queries.GetIntFromQuery(@"Select Qty From PD_tbl_jobs_normal where ID=@ID", idParameters);

              //Material until the hour

              SqlParameter[] hourParameters = new SqlParameter[]{
                new SqlParameter("@ID",SqlDbType.Int) {Value = (int)rowPN["JobID"]},
                new SqlParameter("@JobType",SqlDbType.Int) {Value = (int)rowPN["JobType"]},
                new SqlParameter("@JobSide",SqlDbType.VarChar) {Value = rowPN["JobSide"].ToString()},
                new SqlParameter("@AreaID",SqlDbType.Int) {Value = Model.AreaID},
                new SqlParameter("@trnDate",SqlDbType.DateTime) {Value = seguida.AddHours(+1)}
              };

              int JobBuilded = Firstronic.Framework.Queries.GetIntFromQuery(@"SELECT Count(ssn) as Qty From PD_tbl_units_tracking WITH(INDEX(idx_Job_Balance)) WHERE IsRework='FALSE' AND JobID=@ID AND JobType=@JobType AND JobSide=@JobSide AND AreaID=@AreaID AND trnDate<@trnDate", hourParameters);

              if ((int)rowPN["JobType"] == 2)
              {
                dtBalance.Rows.Add(seguida.Hour.ToString() + " - " + seguida.AddHours(+1).Hour.ToString(), "KB " + rowPN["Job"].ToString(), rowPN["PartNumber"].ToString() + " " + rowPN["JobSide"].ToString(), rowPN["Qty"].ToString(), JobSize - JobBuilded, "");
              }
              else
              {
                dtBalance.Rows.Add(seguida.Hour.ToString() + " - " + seguida.AddHours(+1).Hour.ToString(), rowPN["Job"].ToString(), rowPN["PartNumber"].ToString() + " " + rowPN["JobSide"].ToString(), rowPN["Qty"].ToString(), JobSize - JobBuilded, "");
              }
            }
          }
          else
          {
            dtBalance.Rows.Add(seguida.Hour.ToString() + " - " + seguida.AddHours(+1).Hour.ToString(), "", "", "", "", "");
          }

          seguida = seguida.AddHours(-1);
        }

        DateTime a = DateTime.Now;
        DateTime b = Station.LastPieceTime;

        TimeSpan diff = a - b;
        int Time = (int)Math.Floor(diff.TotalSeconds);

        int Hrs;  // Horas'
        int Min;  // Minuros'
        int Sec;  // Segundos'
        Sec = Time % 60;
        Min = (int)((Time - Sec) / (double)60) % 60;
        Hrs = (int)((Time - (Sec + (Min * 60))) / (double)3600) % 96; // (Maximo 4 dias)
        string TimeInFormat = Hrs.ToString() + " h " + Min.ToString() + " m";

        <div class="uk-width-1-3@l uk-width-1-2@s">
          <div class="dashboard-widget dashboard-widget-top-blue">
            <div class="dashboard-widget-title text-center fs-14 fw-600">
              @Station.StationName (Last Unit @TimeInFormat.ToString())
            </div>
            <div class="dashboard-widget-content">
              <div class="col-12 mvc-grid">
                <table border="1">
                  <thead>
                    <tr>
                      @foreach (System.Data.DataColumn col in dtBalance.Columns)
                      {
                        <th>@col.Caption</th>
                      }
                    </tr>
                  </thead>
                  <tbody>
                    @foreach (System.Data.DataRow row2 in dtBalance.Rows)
                    {
                      <tr>
                        @{
                          int varcell1 = 1;
                        }
                        @foreach (var cell in row2.ItemArray)
                        {
                          <td>@cell.ToString() </td>
                          varcell1++;
                        }
                      </tr>
                    }
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      }
    </div>
  </div>
</div>

<script type="text/javascript" nonce="@Html.ScriptNonce()">

  $(document).ready(function () {
    setInterval(function () {
      cache_clear()
    }, 300000);
  });

  function cache_clear() {
    window.location.reload(true);
    // window.location.reload(); use this if you do not remove cache
  }
</script>

