  .current-time-indicator[style] {
    left: var(--current-time-left, 0);
  }

  .tooltip[style] {
    left: var(--tooltip-left, 0);
    top: var(--tooltip-top, 0);
  }

  .timeline-grid[style],
  .time-marker-container[style] {
    min-width: var(--grid-width, 3000px);
  }

  .tooltip-row {
    margin: 4px 0;
  }

  .tooltip-label {
    font-weight: 600;
    color: #64b5f6;
  }

  /* Job color variations */
  .timeline-job:nth-child(3n+1) {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  }

