<style nonce="@Html.ScriptNonce()">
  .timeline-container {
    background: #ffffff;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    overflow: hidden;
  }

  .timeline-header {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    padding: 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
  }

  .timeline-controls {
    display: flex;
    gap: 10px;
  }

  .timeline-btn {
    background: rgba(255,255,255,0.2);
    border: 1px solid rgba(255,255,255,0.3);
    color: white;
    padding: 8px 16px;
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.3s;
  }

  .timeline-btn:hover {
    background: rgba(255,255,255,0.3);
  }

  .timeline-wrapper {
    overflow-x: auto;
    overflow-y: auto;
    max-height: calc(100vh - 250px);
