    transition: all 0.3s;
  }

  .timeline-btn:hover {
    background: rgba(255,255,255,0.3);
  }

  .timeline-wrapper {
    overflow-x: auto;
    overflow-y: auto;
    max-height: calc(100vh - 250px);
