  .timeline-grid {
    position: relative;
    padding: 20px;
  }

  .timeline-row {
    display: flex;
    margin-bottom: 20px;
    align-items: stretch;
    min-height: 60px;
    border-bottom: 1px solid #e0e0e0;
    padding-bottom: 10px;
  }

  .timeline-station-label {
    width: 200px;
    flex-shrink: 0;
    padding: 10px;
    background: #f8f9fa;
    border-radius: 4px;
    margin-right: 20px;
    display: flex;
    flex-direction: column;
    justify-content: center;
  }

  .station-name {
    font-weight: 600;
