  }

  .time-marker-container {
    display: flex;
    position: relative;
  }

  .time-marker {
    width: 100px;
    text-align: center;
    font-size: 11px;
    color: #666;
    border-left: 1px solid #ddd;
    padding: 5px 0;
    display: flex;
