  .legend-color.priority-3 { background: #BF0001; }
  .legend-color.priority-2 { background: #FFFF00; }
  .legend-color.priority-1 { background: #8FCD2A; }
  .legend-color.priority-0 { background: #6FC3DB; }
  .legend-color.priority-4 { background: #FFFFFF; border: 1px solid #ddd; }
