<script type="text/javascript" nonce="@Html.ScriptNonce()">
  let pixelsPerMinute = 2; // Default zoom level
  const startOfDay = new Date(); // Use current time as start reference
  startOfDay.setMinutes(0, 0, 0); // Round down to current hour

  $(document).ready(function () {
    initializeTimeline();
    positionJobs();
    generateTimeMarkers();
    setupTooltips();
    attachButtonEvents();

    // Auto-refresh every 5 minutes
    setInterval(function () {
      window.location.reload(true);
    }, 300000);
  });

  function attachButtonEvents() {
    document.getElementById('btnCurrentTime').addEventListener('click', scrollToNow);
    document.getElementById('btnZoomIn').addEventListener('click', zoomIn);
    document.getElementById('btnZoomOut').addEventListener('click', zoomOut);
  }

  function initializeTimeline() {
    updateCurrentTimeIndicator();
  }

  function updateCurrentTimeIndicator() {
    // Remove existing indicator if present
    const existing = document.querySelector('.current-time-indicator');
    if (existing) {
      existing.remove();
    }

    // Position current time indicator
    const now = new Date();
    const minutesSinceStart = (now - startOfDay) / (1000 * 60);
    const leftPosition = minutesSinceStart * pixelsPerMinute;

    const indicator = document.createElement('div');
    indicator.className = 'current-time-indicator';
    indicator.style.setProperty('--current-time-left', leftPosition + 'px');
    document.querySelector('.timeline-grid').appendChild(indicator);

    console.log('Current time indicator at:', leftPosition, 'px (', minutesSinceStart, 'min since start)');
  }

  function positionJobs() {
    $('.timeline-job').each(function () {
      const $job = $(this);
      const startTime = new Date($job.data('start'));
      const duration = $job.data('duration');

      const minutesSinceStart = (startTime - startOfDay) / (1000 * 60);
      const leftPosition = minutesSinceStart * pixelsPerMinute;
      const width = duration * pixelsPerMinute;

      // Use setProperty to set CSS custom properties
      this.style.setProperty('--job-left', leftPosition + 'px');
      this.style.setProperty('--job-width', Math.max(width, 80) + 'px');

      // Debug log
      console.log('Job:', $job.data('job'), 'Start:', startTime, 'Left:', leftPosition, 'Width:', width);
    });

    // Update grid width
    const jobTimes = $('.timeline-job').map(function () {
      const start = new Date($(this).data('start'));
      const duration = $(this).data('duration');
      return ((start - startOfDay) / (1000 * 60)) + duration;
    }).get();

    const maxTime = jobTimes.length > 0 ? Math.max(...jobTimes) : 1440; // Default to 24 hours if no jobs
    const gridWidth = Math.max(maxTime * pixelsPerMinute, 3000);

    $('.timeline-grid, .time-marker-container').each(function() {
      this.style.setProperty('--grid-width', gridWidth + 'px');
    });

    console.log('Grid width:', gridWidth, 'Max time:', maxTime, 'Jobs:', jobTimes.length);
  }

  function generateTimeMarkers() {
    const $container = $('#timeMarkers .time-marker-container');
    if ($container.length === 0) {
      $('#timeMarkers').html('<div class="time-marker-container"></div>');
    }

    const container = $('#timeMarkers .time-marker-container');
    container.empty();

    const baseTime = new Date(startOfDay);

    // Each hour marker should be 60 minutes wide at current zoom
    const markerWidth = 60 * pixelsPerMinute;

    // Generate markers for 48 hours from start time
    for (let i = 0; i < 48; i++) {
      const markerTime = new Date(baseTime.getTime() + (i * 60 * 60 * 1000));
      const hour = markerTime.getHours();
      const day = markerTime.getDate();
      const month = markerTime.getMonth() + 1;

      const displayHour = hour === 0 ? '12 AM' : hour < 12 ? hour + ' AM' : hour === 12 ? '12 PM' : (hour - 12) + ' PM';
      const displayDay = month + '/' + day;

      const marker = document.createElement('div');
      marker.className = 'time-marker';
      marker.style.setProperty('--marker-width', markerWidth + 'px');
      marker.innerHTML = `
        <div class="time-marker-hour">${displayHour}</div>
        <div class="time-marker-day">${displayDay}</div>
      `;
      container[0].appendChild(marker);
    }

    console.log('Time markers updated - Width per hour:', markerWidth, 'px');
  }

  function setupTooltips() {
    const $tooltip = $('#tooltip');
    const tooltip = document.getElementById('tooltip');

    $('.timeline-job').hover(
      function (e) {
        const $job = $(this);
        const job = $job.data('job');
        const pn = $job.data('pn');
        const qty = $job.data('qty');
        const start = new Date($job.data('start'));
        const duration = $job.data('duration');
        const end = new Date(start.getTime() + duration * 60000);

        const priority = $job.data('priority');
        const priorityLabel = getPriorityLabel(priority);

        const content = `
          <div class="tooltip-row"><span class="tooltip-label">Job:</span> ${job}</div>
          <div class="tooltip-row"><span class="tooltip-label">Part Number:</span> ${pn}</div>
          <div class="tooltip-row"><span class="tooltip-label">Quantity:</span> ${qty}</div>
          <div class="tooltip-row"><span class="tooltip-label">Priority:</span> ${priorityLabel}</div>
          <div class="tooltip-row"><span class="tooltip-label">Start:</span> ${formatTime(start)}</div>
          <div class="tooltip-row"><span class="tooltip-label">End:</span> ${formatTime(end)}</div>
          <div class="tooltip-row"><span class="tooltip-label">Duration:</span> ${formatDuration(duration)}</div>
        `;

        $tooltip.find('.tooltip-content').html(content);
        $tooltip.addClass('visible');
        updateTooltipPosition(e);
      },
      function () {
        $tooltip.removeClass('visible');
      }
    ).mousemove(updateTooltipPosition);
  }

  function updateTooltipPosition(e) {
    const tooltip = document.getElementById('tooltip');
    const offset = 15;
    tooltip.style.setProperty('--tooltip-left', (e.pageX + offset) + 'px');
    tooltip.style.setProperty('--tooltip-top', (e.pageY + offset) + 'px');
  }

  function formatTime(date) {
    const hours = date.getHours();
    const minutes = date.getMinutes();
    const ampm = hours >= 12 ? 'PM' : 'AM';
    const displayHours = hours % 12 || 12;
    return `${displayHours}:${minutes.toString().padStart(2, '0')} ${ampm}`;
  }

  function formatDuration(minutes) {
    const hours = Math.floor(minutes / 60);
    const mins = minutes % 60;
    if (hours > 0) {
      return `${hours}h ${mins}m`;
    }
    return `${mins}m`;
  }

  function getPriorityLabel(priority) {
    switch(priority) {
      case 3: return 'Critical (3)';
      case 2: return 'High (2)';
      case 1: return 'Medium (1)';
      case 0: return 'Normal (0)';
      case 4: return 'Low (4)';
      case 5: return 'On Hold (5)';
      default: return priority;
    }
  }

  function scrollToNow() {
    const now = new Date();
    const minutesSinceStart = (now - startOfDay) / (1000 * 60);
    // Start timeline at current time (no offset)
    const scrollPosition = Math.max((minutesSinceStart * pixelsPerMinute), 0);

    console.log('Scroll to now - Minutes since start:', minutesSinceStart, 'Scroll position:', scrollPosition);

    const wrapper = document.getElementById('timelineWrapper');
    if (wrapper) {
      wrapper.scrollTo({
        left: scrollPosition,
        behavior: 'smooth'
      });
    } else {
      console.error('Timeline wrapper not found');
    }
  }

  function zoomIn() {
    pixelsPerMinute *= 1.5;
    positionJobs();
    generateTimeMarkers();
    updateCurrentTimeIndicator();
  }

  function zoomOut() {
    pixelsPerMinute = Math.max(pixelsPerMinute / 1.5, 0.5);
    positionJobs();
    generateTimeMarkers();
    updateCurrentTimeIndicator();
  }

  // Auto-scroll to current time on load (start at left edge)
  setTimeout(function() {
    console.log('Setting initial scroll position to 0 (current time at left)...');
    const wrapper = document.getElementById('timelineWrapper');
    if (wrapper) {
      wrapper.scrollLeft = 0;
    }
  }, 500);
</script>

