public ActionResult Balance(int? AreaID = 1, int Building_Key = 0, int year = 0, int month = 0, int day = 0)
{
  var model = new Building_Selector();

  if (year == 0 || month == 0 || day == 0)
  {
    year = DateTime.Now.Year;
    month = DateTime.Now.Month;
    day = DateTime.Now.Day;
  }

  model.month = month;
  model.year = year;
  model.day = day;
  model.AreaID = AreaID;
  model.Building_Key = Building_Key;

  SqlParameter[] areaParameters = new SqlParameter[]{
    new SqlParameter("@AreaID",SqlDbType.Int) {Value = model.AreaID},
    new SqlParameter("@Building_Key",SqlDbType.Int) {Value = model.Building_Key},
  };

  DataTable dt_workcentersoee = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT PD_idt_stations.StationID, PD_idt_stations.StationName, PD_idt_stations.AreaID, PD_idt_stations.IsActive, PD_idt_stations.DownTimeCodeID, PD_idt_stations.LastPieceTime, PD_idt_stations.LastPartID, PD_idt_stations.LastJob, PD_idt_stations.LastJobText, PD_idt_stations.LastJobType, PD_idt_stations.LastJobQty, PD_idt_stations.LastJobQtyBuild, PD_idt_stations.LastHourQty, PD_idt_stations.LastRate, PD_idt_stations.LastSide, PD_idt_stations.BeFirstActive, PD_idt_stations.LockStatus, PD_idt_stations.LastFormat, PD_idt_stations.DashVisible, PD_idt_stations.ProdVisible, PD_idt_stations.LockMachines, PD_idt_stations.Alias, PD_idt_stations.LastBinID, PD_idt_stations.PLC_Name, PD_idt_stations.Workcenter_Key, PD_idt_stations.Workcenter_Key_Kanban, PD_idt_stations.Workcenter_PLC_Name, PD_idt_stations.Workcenter_PLC_Name_Kanban, PD_idt_stations.AutoID, PD_idt_stations.Facility_Key, PD_idt_stations.Allow_Plex_Transactions, PD_idt_stations.Workcenter_Key_1, PD_idt_stations.Workcenter_Key_2, PD_idt_stations.Workcenter_Key_Kanban_1, PD_idt_stations.Workcenter_Key_Kanban_2, PD_idt_stations.Workcenter_PLC_Name_1, PD_idt_stations.Workcenter_PLC_Name_2, PD_idt_stations.Workcenter_PLC_Name_Kanban_1, PD_idt_stations.Workcenter_PLC_Name_Kanban_2, PD_idt_stations.Allow_LoadMaterial, PD_idt_stations.Custom_Labels, PD_idt_stations.Allow_Plex_Transactions_2, CS_idt_partnumbers.PartNumber, EN_idt_downtimes_codes.RazonSpecific,datediff(MINUTE,LastPieceTime,GETDATE()) as Downtime  FROM PD_idt_stations LEFT JOIN  CS_idt_partnumbers ON PD_idt_stations.LastPartID = CS_idt_partnumbers.PartID LEFT JOIN EN_idt_downtimes_codes ON PD_idt_stations.DownTimeCodeID = EN_idt_downtimes_codes.DownTimeCodeID WHERE (PD_idt_stations.AreaID = @AreaID) AND (PD_idt_stations.BeFirstActive = 1) AND (PD_idt_stations.StationID not in (SELECT [Sub_Station_ID] FROM [Part_Station_SubStation] WHERE Station_ID<>Sub_Station_ID) ) AND (@Building_Key=0 or PD_idt_stations.Building_Key=@Building_Key) Order by PD_idt_stations.Building_Key ASC,PD_idt_stations.SortNo ASC, StationName ASC", areaParameters);

