    string StationName = rowParts["StationName"].ToString();
    DateTime LastPieceTime = (DateTime)rowParts["LastPieceTime"];

    listStations.Add(new tbl_PART_Station() { StationID = StationID, StationName = StationName, LastPieceTime = LastPieceTime });
  }

  model.listStations = listStations;

  return View(model);
}

